namespace sv_0418ff6761ac4c4188123143ba4d11b6.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public record StatusUpdate(string Status, string Location, DateTimeOffset Timestamp);

using System.Net.Http.Json;

namespace sv_0418ff6761ac4c4188123143ba4d11b6.Client.Services;

public sealed class HttpShipmentService : IShipmentService
{
    private readonly HttpClient _http;

    public HttpShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var result = await _http.GetFromJsonAsync<ShipmentDetails>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        return result ?? throw new InvalidOperationException("Shipment not found.");
    }
}

using sv_0418ff6761ac4c4188123143ba4d11b6.Client.Services;

namespace sv_0418ff6761ac4c4188123143ba4d11b6.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            DateTimeOffset.UtcNow.AddDays(2),
            new List<StatusUpdate>
            {
                new("Order Placed", "New York, NY", DateTimeOffset.UtcNow.AddDays(-3)),
                new("Picked Up", "New York, NY", DateTimeOffset.UtcNow.AddDays(-2)),
                new("In Transit", "Chicago, IL", DateTimeOffset.UtcNow.AddDays(-1))
            }),
        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "San Francisco, CA",
            DateTimeOffset.UtcNow.AddDays(-1),
            new List<StatusUpdate>
            {
                new("Order Placed", "Seattle, WA", DateTimeOffset.UtcNow.AddDays(-5)),
                new("Picked Up", "Seattle, WA", DateTimeOffset.UtcNow.AddDays(-4)),
                new("In Transit", "Portland, OR", DateTimeOffset.UtcNow.AddDays(-3)),
                new("Out for Delivery", "San Francisco, CA", DateTimeOffset.UtcNow.AddDays(-1)),
                new("Delivered", "San Francisco, CA", DateTimeOffset.UtcNow.AddDays(-1))
            }),
        ["TRK-003"] = new ShipmentDetails(
            "TRK-003",
            "Processing",
            "Dallas, TX",
            DateTimeOffset.UtcNow.AddDays(5),
            new List<StatusUpdate>
            {
                new("Order Placed", "Dallas, TX", DateTimeOffset.UtcNow.AddHours(-6)),
                new("Processing", "Dallas, TX", DateTimeOffset.UtcNow.AddHours(-2))
            })
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Tracking number '{trackingNumber}' not found.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_0418ff6761ac4c4188123143ba4d11b6.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment <strong>@TrackingNumber</strong>…</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status History</h3>
    <table class="table">
        <thead>
            <tr>
                <th>Time</th>
                <th>Status</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.Updates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Status</td>
                    <td>@update.Location</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or disposed — silently abandon
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

